// ❌ Jangan kirim input user mentah ke HTML
// res.send(`<h1>${req.query.name}</h1>`);

// ✅ Escape/encode output user
const escapeHtml = (value) => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

res.send(`<h1>${escapeHtml(req.query.name)}</h1>`);

